// n8n Code node (Node.js)
// Builds: { subject, html, attachments[], binary }

const rec = $json?.body?.record ?? $json?.record ?? {};

/* =========================
   THEME
   ========================= */
const THEME = {
  headerBg: "#f58220",
  headerText: "#ffffff",
  labelBg: "#FFF7D9",
  border: "#e6e6e6",
  pageBg: "#f6f6f6",
  cardBg: "#ffffff",
  text: "#1f1f1f",
  muted: "#666666",
  link: "#1a73e8",
};

/* ---------------- helpers ---------------- */
function escapeHtml(v) {
  return String(v ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function asText(value, fb = "") {
  if (value === undefined || value === null) return fb;

  // Handle Arrays (e.g. Linked Records)
  if (Array.isArray(value)) {
    if (!value.length) return fb;
    if (typeof value[0] === "object" && value[0] !== null) {
      const names = value
        .map(v => (v && typeof v === "object" && "name" in v ? v.name : null))
        .filter(Boolean);
      return names.length ? String(names.join(", ")) : JSON.stringify(value);
    }
    return String(value.join(", "));
  }

  // Handle Objects (e.g. Single Selects or Lookup Objects)
  if (typeof value === "object") {
    if ("name" in value) return String(value.name);
    return JSON.stringify(value);
  }

  return String(value);
}

function formatDate(value) {
  const raw = asText(value, "").trim();
  if (!raw) return "";
  const d = new Date(raw);
  if (Number.isNaN(d.getTime())) return raw;
  return d.toLocaleDateString("en-US", { year: "numeric", month: "long", day: "2-digit" });
}

function formatMoney(v) {
  const raw = asText(v, "").trim();
  if (!raw) return "";
  const n = Number(raw.replace(/[^0-9.-]/g, ""));
  if (Number.isNaN(n)) return raw;
  return `$${n.toLocaleString("en-US", { minimumFractionDigits: 0, maximumFractionDigits: 0 })}`;
}

function companyAddress() {
  const billing = asText(rec["Billing Address"], "").trim();
  if (billing) return billing;
  const city = asText(rec["City"], "").trim();
  const state = asText(rec["State"], "").trim();
  const zip = asText(rec["Zip code"], "").trim();
  const parts = [city, state, zip].filter(Boolean);
  return parts.length ? parts.join(", ") : "";
}

function plainValueToHtml(v) {
  const raw = asText(v, "").trim();
  if (!raw) return "—";
  const safe = escapeHtml(raw);
  if (/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(raw)) {
    return `<a href="mailto:${safe}" style="color:${THEME.link};text-decoration:underline;">${safe}</a>`;
  }
  if (/^https?:\/\/\S+$/i.test(raw)) {
    return `<a href="${safe}" target="_blank" style="color:${THEME.link};text-decoration:underline;">${safe}</a>`;
  }
  return safe;
}

function inlineMarkdownToHtml(text) {
  let s = escapeHtml(text ?? "");
  s = s.replace(
    /\[([^\]]+)\]\((https?:\/\/[^\s)]+)\)/g,
    `<a href="$2" target="_blank" style="color:${THEME.link};text-decoration:underline;">$1</a>`
  );
  s = s.replace(
    /(^|[^"'=<>])(https?:\/\/[^\s<]+)/g,
    (m, lead, url) =>
      `${lead}<a href="${url}" target="_blank" style="color:${THEME.link};text-decoration:underline;">${url}</a>`
  );
  s = s.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>");
  s = s.replace(/(^|[\s>])_([^_]+)_/g, '$1<em>$2</em>');
  s = s.replace(/\n/g, "<br>");
  return s || "—";
}

function markdownToHtml(md) {
  const raw = asText(md, "");
  if (!raw.trim()) return "—";
  const lines = raw.replace(/\r\n/g, "\n").split("\n");
  let html = "";
  let listLevel = 0;
  let para = [];
  const closeListsTo = (level) => {
    while (listLevel > level) {
      html += "</ul>";
      listLevel--;
    }
  };
  const flushPara = () => {
    if (!para.length) return;
    html += `<p style="margin:0 0 10px 0;line-height:1.55;">${inlineMarkdownToHtml(para.join("\n"))}</p>`;
    para = [];
  };
  const bulletRegex = /^(\s*)([-•])\s+(.*)$/;
  const headingRegex = /^(#{1,4})\s+(.*)$/;
  for (const line of lines) {
    const h = line.match(headingRegex);
    if (h) {
      flushPara();
      closeListsTo(0);
      const level = h[1].length;
      const text = (h[2] || "").trim();
      const size = level === 1 ? 18 : level === 2 ? 16 : level === 3 ? 15 : 14;
      html += `<div style="margin:12px 0 8px 0;font-weight:700;font-size:${size}px;line-height:1.3;">${inlineMarkdownToHtml(text)}</div>`;
      continue;
    }
    const m = line.match(bulletRegex);
    if (m) {
      flushPara();
      const indent = (m[1] || "").replace(/\t/g, "    ").length;
      const level = Math.floor(indent / 4) + 1;
      const item = (m[3] || "").trim();
      if (!item) continue;
      if (level > listLevel) {
        while (listLevel < level) {
          html += `<ul style="margin:0 0 10px 22px;padding:0;line-height:1.55;">`;
          listLevel++;
        }
      } else if (level < listLevel) {
        closeListsTo(level);
      }
      html += `<li style="margin:0 0 6px 0;">${inlineMarkdownToHtml(item)}</li>`;
      continue;
    }
    if (!line.trim()) {
      flushPara();
      closeListsTo(0);
      continue;
    }
    para.push(line);
  }
  flushPara();
  closeListsTo(0);
  return html || "—";
}

function section(title, rows) {
  const headerStyle = `background:${THEME.headerBg};color:${THEME.headerText};font-weight:700;text-transform:uppercase;letter-spacing:.4px;text-align:center;padding:12px 10px;font-size:14px;`;
  const tableStyle = `width:100%;border-collapse:collapse;border:1px solid ${THEME.border};font-family:Arial,Helvetica,sans-serif;font-size:14px;`;
  const thStyle = `width:38%;background:${THEME.labelBg};font-weight:700;text-align:left;padding:12px 14px;border-bottom:1px solid ${THEME.border};border-right:1px solid ${THEME.border};vertical-align:top;`;
  const tdStyle = `background:#ffffff;padding:12px 14px;border-bottom:1px solid ${THEME.border};vertical-align:top;`;
  const rowsHtml = rows
    .map(r => {
      const label = escapeHtml(r.label);
      const valueHtml = r.rich ? markdownToHtml(r.value) : plainValueToHtml(r.value);
      return `<tr><th style="${thStyle}">${label}</th><td style="${tdStyle}${r.rich ? "line-height:1.55;" : ""}">${valueHtml}</td></tr>`;
    })
    .join("");
  return `<table role="presentation" cellpadding="0" cellspacing="0" style="${tableStyle}margin:0 0 18px 0;"><tr><td colspan="2" style="${headerStyle}">${escapeHtml(title)}</td></tr>${rowsHtml}</table>`;
}

function collectAttachments(fieldName) {
  const arr = rec?.[fieldName];
  if (!Array.isArray(arr)) return [];
  return arr.filter(a => a && a.url).map(a => ({
    url: a.url,
    filename: a.filename || `${fieldName}`,
    mimeType: a.type || "application/octet-stream",
    size: a.size ?? null,
    field: fieldName,
  }));
}

const attachments = [
  ...collectAttachments("CSA"),
  ...collectAttachments("RFP"),
  ...collectAttachments("SOW"),
  ...collectAttachments("Job Description"),
  ...collectAttachments("Additional Attachments"),
];

const subject = `RFP — ${asText(rec["Company Name"], "Company")} — ${asText(rec["Client Name"], "Client")}`;

const htmlContent = `
<!doctype html>
<html>
<head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>
<body style="margin:0;padding:0;background:${THEME.pageBg};">
  <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:${THEME.pageBg};padding:24px 0;">
    <tr><td align="center">
        <table role="presentation" cellpadding="0" cellspacing="0" style="width:100%;max-width:860px;background:${THEME.cardBg};border:1px solid ${THEME.border};">
          <tr><td style="padding:26px 26px 10px 26px;font-family:Arial,Helvetica,sans-serif;color:${THEME.text};">
              <h1 style="margin:0 0 18px 0;text-align:center;font-size:36px;letter-spacing:.6px;color:${THEME.text};">REQUEST FOR PROCESS ENGINEERING (RFP)</h1>
              ${section("Company Information", [
                { label: "Company Name", value: rec["Company Name"] },
                { label: "Company Email", value: rec["Company Email"] },
                { label: "Company Phone Number", value: rec["Company Phone Number"] },
                { label: "Company Address", value: companyAddress() || "—" },
                { label: "Company Website", value: rec["Company Website"] },
                { label: "Lead Source", value: rec["Lead Source"] },
              ])}
              ${section("Client Information", [
                { label: "Client Name", value: rec["Client Name"] },
                { label: "Client Growth Profile", value: rec["Client Growth Profile"] },
                { label: "Job Title", value: rec["Job Title"] },
                { label: "Client Phone Number", value: rec["Client Phone Number"] },
                { label: "Client Email", value: rec["Client Email"] },
                { label: "Timezone", value: rec["Timezone"] },
              ])}
              ${section("POC Information", [
                { label: "Other Teammates to Join PEC", value: rec["Other Teammates to Join PEC"] },
                { label: "Other Teammate Job Title", value: rec["Other Teammate Job Title"] },
                { label: "POC Phone Number", value: rec["POC Phone Number"] },
                { label: "POC Email", value: rec["POC Email"] },
              ])}
              ${section("RFP Details", [
                { label: "RFP Received Date", value: formatDate(rec["RFP Received Date"]) || "—" },
                { label: "Sales Closer", value: rec["Sales Closer"] },
                { label: "Prepared By", value: rec["Prepared By"] },
                { label: "CSA Signed On", value: formatDate(rec["CSA Signed On"]) || "—" },
                { label: "SUF Paid On", value: formatDate(rec["SUF Paid On"]) || "—" },
                { label: "Total SUF Amount", value: formatMoney(rec["Total SUF Amount"]) || "—" },
                { label: "SUF Scope", value: rec["SUF Scope"] },
                { label: "Requirement Type", value: rec["Requirement Type"] },
                { label: "Client Rate", value: rec["Client Rate"] },
                { label: "Finance Notes", value: rec["Finance Notes"] },
              ])}
              ${section("Notes for PEC", [
                { label: "Type of Client", value: rec["Type of Client"], rich: true },
                { label: "Number of Role(s)", value: rec["Number of Role(s)"] },
                { label: "Tasks", value: rec["Tasks"], rich: true },
                { label: "Pain Points", value: rec["Pain Points"], rich: true },
                { label: "Proposed Solutions", value: rec["Proposed Solutions"], rich: true },
              ])}
              ${section("Other Notes", [
                { label: "Other Notes", value: rec["Other Notes"], rich: true },
                { label: "DC Recording and Summary", value: rec["DC Recording and Summary"], rich: true },
              ])}
              <div style="font-size:12px;color:${THEME.muted};text-align:center;padding:6px 0 0 0;">This email was sent automatically with n8n</div>
            </td></tr>
        </table>
      </td></tr>
  </table>
</body></html>`;

// === KEY STEP: Convert to Binary ===
const base64String = Buffer.from(htmlContent).toString('base64');

// Return JSON *and* Binary together
return [{
  json: { 
    subject, 
    html: htmlContent, 
    attachments 
  },
  binary: {
    email_file: {
      data: base64String,
      mimeType: 'text/html',
      fileName: 'RFP_Email_Copy.html'
    }
  }
}];

const items = $input.all();

const out = {
  json: {
    subject: items[0]?.json?.subject || "",
    html: items[0]?.json?.html || "",
  },
  binary: {},
};

const keys = [];

items.forEach((it, idx) => {
  if (!it.binary?.data) return;

  const key = `att_${idx + 1}`;
  out.binary[key] = it.binary.data;

  // preserve filenames + mime types
  if (it.json?.filename) out.binary[key].fileName = it.json.filename;
  if (it.json?.mimeType) out.binary[key].mimeType = it.json.mimeType;

  keys.push(key);
});

out.json.attachmentKeys = keys.join(",");

return [out];

// n8n Code node (Node.js)
// Builds: { subject, html, attachments[] } AND { binary: { email_file } }
// - Orange header fills ONLY
// - Label (left) column fill: #FFF7D9
// - "Company Address" logic
// - SUF Paid Amount formatted with $
// - Rich fields render markdown
// - Attachments pulled from Airtable
// - Generates binary file for immediate upload

const rec = $json?.body?.record ?? $json?.record ?? {};

/* =========================
   THEME
   ========================= */
const THEME = {
  headerBg: "#f58220",
  headerText: "#ffffff",
  labelBg: "#FFF7D9",
  border: "#e6e6e6",
  pageBg: "#f6f6f6",
  cardBg: "#ffffff",
  text: "#1f1f1f",
  muted: "#666666",
  link: "#1a73e8",
};

/* ---------------- helpers ---------------- */
function escapeHtml(v) {
  return String(v ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;")
    .replace(/'/g, "&#039;");
}

function asText(value, fb = "") {
  if (value === undefined || value === null) return fb;

  if (Array.isArray(value)) {
    if (!value.length) return fb;

    if (typeof value[0] === "object" && value[0] !== null) {
      const names = value
        .map(v => (v && typeof v === "object" && "name" in v ? v.name : null))
        .filter(Boolean);
      return names.length ? String(names.join(", ")) : JSON.stringify(value);
    }

    return String(value.join(", "));
  }

  if (typeof value === "object") {
    if ("name" in value) return String(value.name);
    return JSON.stringify(value);
  }

  return String(value);
}

function formatDate(value) {
  const raw = asText(value, "").trim();
  if (!raw) return "";
  const d = new Date(raw);
  if (Number.isNaN(d.getTime())) return raw;
  return d.toLocaleDateString("en-US", { year: "numeric", month: "long", day: "2-digit" });
}

function formatMoney(v) {
  const raw = asText(v, "").trim();
  if (!raw) return "";
  const n = Number(raw.replace(/[^0-9.-]/g, ""));
  if (Number.isNaN(n)) return raw;
  return `$${n.toLocaleString("en-US", { minimumFractionDigits: 0, maximumFractionDigits: 0 })}`;
}

// Prefer Billing Address as-is; Fallback to City/State/Zip
function companyAddress() {
  const billing = asText(rec["Billing Address"], "").trim();
  if (billing) return billing;

  const city = asText(rec["Billing City (from Company Link)"], "").trim();
  const state = asText(rec["Billing State (from Company Link)"], "").trim();
  const zip = asText(rec["Billing Zip Code (from Company Link)"], "").trim();
  const parts = [city, state, zip].filter(Boolean);
  return parts.length ? parts.join(", ") : "";
}

// Plain value renderer (keeps links clickable)
function plainValueToHtml(v) {
  const raw = asText(v, "").trim();
  if (!raw) return "—";
  const safe = escapeHtml(raw);

  // email
  if (/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(raw)) {
    return `<a href="mailto:${safe}" style="color:${THEME.link};text-decoration:underline;">${safe}</a>`;
  }
  // url
  if (/^https?:\/\/\S+$/i.test(raw)) {
    return `<a href="${safe}" target="_blank" style="color:${THEME.link};text-decoration:underline;">${safe}</a>`;
  }
  return safe;
}

// Inline markdown -> HTML (safe)
function inlineMarkdownToHtml(text) {
  let s = escapeHtml(text ?? "");

  // markdown links [text](url)
  s = s.replace(
    /\[([^\]]+)\]\((https?:\/\/[^\s)]+)\)/g,
    `<a href="$2" target="_blank" style="color:${THEME.link};text-decoration:underline;">$1</a>`
  );

  // bare URLs
  s = s.replace(
    /(^|[^"'=<>])(https?:\/\/[^\s<]+)/g,
    (m, lead, url) =>
      `${lead}<a href="${url}" target="_blank" style="color:${THEME.link};text-decoration:underline;">${url}</a>`
  );

  // **bold**
  s = s.replace(/\*\*([^*]+)\*\*/g, "<strong>$1</strong>");
  // _italics_
  s = s.replace(/(^|[\s>])_([^_]+)_/g, '$1<em>$2</em>');
  // line breaks
  s = s.replace(/\n/g, "<br>");

  return s || "—";
}

// Block markdown -> HTML
function markdownToHtml(md) {
  const raw = asText(md, "");
  if (!raw.trim()) return "—";

  const lines = raw.replace(/\r\n/g, "\n").split("\n");
  let html = "";
  let listLevel = 0;
  let para = [];

  const closeListsTo = (level) => {
    while (listLevel > level) {
      html += "</ul>";
      listLevel--;
    }
  };

  const flushPara = () => {
    if (!para.length) return;
    html += `<p style="margin:0 0 10px 0;line-height:1.55;">${inlineMarkdownToHtml(para.join("\n"))}</p>`;
    para = [];
  };

  const bulletRegex = /^(\s*)([-•])\s+(.*)$/;
  const headingRegex = /^(#{1,4})\s+(.*)$/;

  for (const line of lines) {
    const h = line.match(headingRegex);
    if (h) {
      flushPara();
      closeListsTo(0);
      const level = h[1].length;
      const text = (h[2] || "").trim();
      const size = level === 1 ? 18 : level === 2 ? 16 : level === 3 ? 15 : 14;
      html += `<div style="margin:12px 0 8px 0;font-weight:700;font-size:${size}px;line-height:1.3;">${inlineMarkdownToHtml(text)}</div>`;
      continue;
    }

    const m = line.match(bulletRegex);
    if (m) {
      flushPara();
      const indent = (m[1] || "").replace(/\t/g, "    ").length;
      const level = Math.floor(indent / 4) + 1;
      const item = (m[3] || "").trim();
      if (!item) continue;

      if (level > listLevel) {
        while (listLevel < level) {
          html += `<ul style="margin:0 0 10px 22px;padding:0;line-height:1.55;">`;
          listLevel++;
        }
      } else if (level < listLevel) {
        closeListsTo(level);
      }
      html += `<li style="margin:0 0 6px 0;">${inlineMarkdownToHtml(item)}</li>`;
      continue;
    }

    if (!line.trim()) {
      flushPara();
      closeListsTo(0);
      continue;
    }
    para.push(line);
  }
  flushPara();
  closeListsTo(0);
  return html || "—";
}

/* ---------------- section builder ---------------- */
function section(title, rows) {
  const headerStyle =
    `background:${THEME.headerBg};color:${THEME.headerText};font-weight:700;` +
    `text-transform:uppercase;letter-spacing:.4px;text-align:center;padding:12px 10px;font-size:14px;`;
  const tableStyle =
    `width:100%;border-collapse:collapse;border:1px solid ${THEME.border};` +
    `font-family:Arial,Helvetica,sans-serif;font-size:14px;`;
  const thStyle =
    `width:38%;background:${THEME.labelBg};font-weight:700;text-align:left;` +
    `padding:12px 14px;border-bottom:1px solid ${THEME.border};border-right:1px solid ${THEME.border};vertical-align:top;`;
  const tdStyle =
    `background:#ffffff;padding:12px 14px;border-bottom:1px solid ${THEME.border};vertical-align:top;`;

  const rowsHtml = rows
    .map(r => {
      const label = escapeHtml(r.label);
      const valueHtml = r.rich ? markdownToHtml(r.value) : plainValueToHtml(r.value);
      return `<tr>
        <th style="${thStyle}">${label}</th>
        <td style="${tdStyle}${r.rich ? "line-height:1.55;" : ""}">${valueHtml}</td>
      </tr>`;
    })
    .join("");

  return `
    <table role="presentation" cellpadding="0" cellspacing="0" style="${tableStyle}margin:0 0 18px 0;">
      <tr><td colspan="2" style="${headerStyle}">${escapeHtml(title)}</td></tr>
      ${rowsHtml}
    </table>
  `;
}

/* ---------------- attachments ---------------- */
function collectAttachments(fieldName) {
  const arr = rec?.[fieldName];
  if (!Array.isArray(arr)) return [];
  return arr
    .filter(a => a && a.url)
    .map(a => ({
      url: a.url,
      filename: a.filename || `${fieldName}`,
      mimeType: a.type || "application/octet-stream",
      size: a.size ?? null,
      field: fieldName,
    }));
}

const attachments = [
  ...collectAttachments("CSA"),
  ...collectAttachments("RFP"),
  ...collectAttachments("SOW"),
  ...collectAttachments("Job Description"),
];

/* ---------------- content ---------------- */
const companyName = asText(rec["Company Name (from Company Link)"], "Company");
const clientName = asText(rec["Client Name (from Clients Link)"], "Client");
const subject = `RFP — ${companyName} — ${clientName}`;

const html = `
<!doctype html>
<html>
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width,initial-scale=1">
</head>
