const items = $input.all();

const out = {
  json: {
    subject: items[0]?.json?.subject || "",
    html: items[0]?.json?.html || "",
  },
  binary: {},
};

const keys = [];

items.forEach((it, idx) => {
  if (!it.binary?.data) return;

  const key = `att_${idx + 1}`;
  out.binary[key] = it.binary.data;

  // preserve filenames + mime types
  if (it.json?.filename) out.binary[key].fileName = it.json.filename;
  if (it.json?.mimeType) out.binary[key].mimeType = it.json.mimeType;

  keys.push(key);
});

out.json.attachmentKeys = keys.join(",");

return [out];

// n8n Code node (Node.js)
// Returns ONLY the calculated IDs and loop numbers.
// (Removes all original input data to keep output clean)

function firstId(v) {
  if (!v) return "";
  const x = Array.isArray(v) ? v[0] : v;
  if (!x) return "";
  if (typeof x === "object") return String(x.id ?? x.recordId ?? "");
  return String(x);
}

return $input.all().flatMap(({ json }) => {
  // 1. GET THE COUNT
  // Checks "roleNumber" first (from your input), falls back to "Number of Role(s)"
  const rawCount = json["roleNumber"] ?? json["Number of Role(s)"];
  const rolesTotal = Math.max(Number(rawCount) || 1, 1);

  // 2. EXTRACT IDS
  // Pulls the first ID from the arrays (e.g. ["rec..."] -> "rec...")
  const clientRecordId  = firstId(json["Client"] || json["Clients"]); 
  const companyRecordId = firstId(json["Company"]);
  const pocRecordId     = firstId(json["POC"]);

  // 3. CREATE CLEAN OUTPUT
  return Array.from({ length: rolesTotal }, (_, i) => ({
    json: {
      clientRecordId,
      companyRecordId,
      pocRecordId,
      roleIndex: i + 1,
      rolesTotal,
    },
  }));
});

